import requests
import os
import json


class Tools:
    @staticmethod
    def run(
        service: str,
        action: str,
        query: str = None,
        identifier: str = None,
        params: dict = None,
    ) -> dict:
        """
        Unified academic paper/metadata tool.

        Parameters:
        - service: one of "semanticscholar", "openalex", "core", "connectedpapers", "ncbi"
        - action: "search", "get_paper", "citations", "references", "author"
        - query: search string (for search action)
        - identifier: paperId, DOI, PMID, OpenAlex ID, etc. (for get_paper/citations/etc)
        - params: optional extra query params as dict

        Uses corresponding API key from environment.
        Returns JSON result or error dict.
        """
        service = service.lower()
        api_key = None
        base_url = None
        headers = {"Accept": "application/json"}

        if service == "semanticscholar":
            api_key = os.environ.get("SEMANTIC_SCHOLAR_API_KEY")
            base_url = "https://api.semanticscholar.org/graph/v1"
            if not api_key:
                return {"error": "SEMANTIC_SCHOLAR_API_KEY not found"}

        elif service == "openalex":
            api_key = os.environ.get("OPENALEX_API_KEY")
            base_url = "https://api.openalex.org"
            headers["User-Agent"] = (
                "YourApp (mailto:your@email.com)"  # OpenAlex requires UA + email
            )
            if api_key:
                headers["x-api-key"] = api_key

        elif service == "core":
            api_key = os.environ.get("CORE_API_KEY")
            base_url = "https://api.core.ac.uk/v3"
            if not api_key:
                return {"error": "CORE_API_KEY not found"}

        elif service == "connectedpapers":
            api_key = os.environ.get("CONNECTED_PAPERS_API_KEY")
            base_url = "https://api.connectedpapers.com"
            if not api_key:
                return {"error": "CONNECTED_PAPERS_API_KEY not found"}

        elif service == "ncbi":
            api_key = os.environ.get("NCBI_API_KEY")
            base_url = "https://eutils.ncbi.nlm.nih.gov/entrez/eutils"
            if not api_key:
                return {"error": "NCBI_API_KEY not found"}

        else:
            return {
                "error": f"Unknown service: {service}. Supported: semanticscholar, openalex, core, connectedpapers, ncbi"
            }

        if not base_url:
            return {"error": "No base URL configured for service"}

        endpoint = ""
        method = "GET"
        payload = None

        if action == "search":
            if service == "semanticscholar":
                endpoint = "paper/search"
                params = params or {}
                params["query"] = query
                params["limit"] = params.get("limit", 10)
                params["fields"] = params.get(
                    "fields",
                    "title,abstract,authors,year,venue,journal,citationCount,externalIds,openAccessPdf",
                )
            elif service == "openalex":
                endpoint = "works"
                params = params or {}
                params["search"] = query
                params["per-page"] = params.get("per-page", 10)
            elif service == "core":
                endpoint = "search"
                params = params or {}
                params["q"] = query
            # ... add more services as needed

        elif action in ["get_paper", "citations", "references"]:
            if not identifier:
                return {
                    "error": "identifier required for get_paper/citations/references"
                }
            if service == "semanticscholar":
                if action == "get_paper":
                    endpoint = f"paper/{identifier}"
                elif action == "citations":
                    endpoint = f"paper/{identifier}/citations"
                elif action == "references":
                    endpoint = f"paper/{identifier}/references"
            elif service == "openalex":
                endpoint = f"works/{identifier}"
                if action in ["citations", "references"]:
                    return {
                        "error": "Use 'cited_by' or 'referenced_works' fields in OpenAlex instead"
                    }

        else:
            return {"error": f"Unknown action: {action}"}

        try:
            if method == "GET":
                response = requests.get(
                    f"{base_url}/{endpoint.lstrip('/')}",
                    headers=headers,
                    params=params,
                    timeout=15,
                )
            else:
                response = requests.post(
                    f"{base_url}/{endpoint.lstrip('/')}",
                    headers=headers,
                    json=payload,
                    timeout=15,
                )

            response.raise_for_status()
            data = response.json()

            # Optional: enrich with direct URLs when missing
            if service == "semanticscholar" and "data" in data:
                for paper in data.get("data", []):
                    if "paperId" in paper and "url" not in paper:
                        paper["url"] = (
                            f"https://www.semanticscholar.org/paper/{paper['paperId']}"
                        )

            return data

        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": (
                    getattr(e.response, "status_code", None)
                    if hasattr(e, "response")
                    else None
                ),
                "response_text": (
                    getattr(e.response, "text", "")[:500]
                    if hasattr(e, "response")
                    else ""
                ),
            }
